import { cn } from '@/utils/cn';
import { For, Match, mergeProps, Show, Switch, type Component } from 'solid-js';
import { Button } from '../button';
import type { FloatButtonProps } from './float-button.types';

const DEFAULT_PROPS: FloatButtonProps = {
  type: 'default',
  color: 'var(--color-warning)',
  size: 24,
  animate: 'none',
  closeIcon: {
    label: 'Close',
    icon: 'X',
  },
};

export function renderAnimateClass(animate: string | undefined) {
  const AnimateInfinite: Record<string, string> = {
    ripple: 'animate-ripple',
    pulse: 'animate-pulse',
    bounce: 'animate-bounce',
    heartBeat: 'animate-heartBeat',
    headShake: 'animate-headShake',
    swing: 'animate-swing',
    jello: 'animate-jello',
  };
  return animate ? AnimateInfinite[animate] : '';
}
function renderBadgeWidth(count: number): string {
  if (count >= 10_000) return 'px-1 translate-x-2';
  if (count >= 1000) return 'px-1 translate-x-1 -translate-y-1';
  if (count >= 100) return 'px-1';
  return 'w-5';
}
const FloatButtonBadge: Component<{
  badge?: FloatButtonProps['badge'];
}> = p => {
  return (
    <div class="absolute -top-2 -right-2">
      <div
        class={cn(
          'bg-error flex h-5 cursor-pointer rounded-full text-xs text-white *:m-auto',
          renderBadgeWidth(p.badge?.count!),
          p.badge?.animate && `animate-${p.badge?.animate}`,
          p.badge?.class,
        )}
      >
        {p.badge?.count && <div>{p.badge?.count}</div>}
      </div>
    </div>
  );
};

export const FloatButton: Component<FloatButtonProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);
  const size = `${p.size}px`;

  return (
    <Switch>
      <Match when={p.type === 'single'}>
        <div class={cn('fab pointer-events-auto', p.class)} onClick={p.onClickOpen}>
          <div class="relative">
            <Button
              icon={p.icon}
              variant="solid"
              shape="circle"
              class={cn('fab-open border-0', renderAnimateClass(p.animate))}
              tabIndex={0}
              style={{
                'background-color': p.color,
                width: size,
                height: size,
                ['--innner-color']: p.color,
                ['--btn-color']: p.color,
              }}
            />
            <Show when={p.badge?.count}>
              <FloatButtonBadge badge={p.badge} />
            </Show>
          </div>
        </div>
      </Match>
      <Match when={p.type !== 'single'}>
        <div class={cn('fab', p.type === 'flower' && 'fab-flower', p.class)}>
          <div class="relative" tabIndex={0}>
            <Button
              icon={p.icon}
              variant="solid"
              shape="circle"
              class={cn('fab-open border-0', renderAnimateClass(p.animate))}
              style={{
                'background-color': p.color,
                width: size,
                height: size,
                ['--innner-color']: p.color,
              }}
            />
            <Show when={p.badge?.count}>
              <FloatButtonBadge badge={p.badge} />
            </Show>
          </div>

          <div class="fab-close">
            {p.type === 'default' && p.closeIcon?.label}
            <div
              class="float-close btn btn-circle btn-error"
              style={{ width: size, height: size }}
              onClick={p.closeIcon?.onClickClose}
            >
              {(p.closeIcon?.icon as Element) ?? 'orange'}
            </div>
          </div>
          <Switch>
            <Match when={p.type === 'default'}>
              <div class="float-menu flex flex-col items-end">
                <For each={p.actions}>
                  {item => {
                    return <div class="flex gap-2">{item as Element}</div>;
                  }}
                </For>
              </div>
            </Match>
            <Match when={p.type === 'flower'}>
              <For each={p.actions}>
                {(item, index) => {
                  if (index() > 3) {
                    console.warn(
                      'Chỉ có thể nhận tối đa 4 component. Cần xóa các Component sau: ',
                      item,
                    );
                    return;
                  }
                  return <>{item}</>;
                }}
              </For>
            </Match>
          </Switch>
        </div>
      </Match>
    </Switch>
  );
};
